      project,
      total_spools: total,
      welded_out_spools: weldedOut,
      percent_welded_out: Number(((weldedOut / total) * 100).toFixed(2))
    };
  }),

  package_metrics: Object.keys(packageTotals).map(pkg => {
    const total = packageTotals[pkg];
    const weldedOut = packageWeldedOut[pkg] || 0;

    return {
      package: pkg,
      total_spools: total,
      welded_out_spools: weldedOut,
      percent_welded_out: Number(((weldedOut / total) * 100).toFixed(2))
    };
  })
};

// ----------------------
// SORTING
// ----------------------
result.project_metrics.sort(
  (a, b) => b.percent_welded_out - a.percent_welded_out
);

result.package_metrics.sort(
  (a, b) => b.percent_welded_out - a.percent_welded_out
);

return result;




